#include <stdio.h>
#include <stdlib.h>

int cmp_int(const void *a, const void *b) {
    int x = *(const int*)a;
    int y = *(const int*)b;
    return (x > y) - (x < y);
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, K; scanf("%d %d", &N, &K);
        int *A = (int*)malloc(N * sizeof(int));
        for(int i=0;i<N;i++) scanf("%d", &A[i]);
        long long ans = 0;
        for(int r=0;r<K;r++){
            // collect elements of this class
            int cnt = 0;
            for(int i=r;i<N;i+=K) cnt++;
            int *tmp = (int*)malloc(cnt * sizeof(int));
            int idx=0;
            for(int i=r;i<N;i+=K) tmp[idx++] = A[i];
            qsort(tmp, cnt, sizeof(int), cmp_int);
            int maxFreq = 1, curFreq = 1;
            for(int i=1;i<cnt;i++){
                if(tmp[i]==tmp[i-1]) curFreq++; else { if(curFreq>maxFreq) maxFreq=curFreq; curFreq=1; }
            }
            if(curFreq>maxFreq) maxFreq=curFreq;
            ans += cnt - maxFreq;
            free(tmp);
        }
        printf("%lld\n", ans);
        free(A);
    }
    return 0;
}

